complete_examples.code:
# Grade system
score = 85

print(f'Your score: {score}')
print('Grade: ', end='')

if score >= 90:
    print('A - Excellent! 🌟')
elif score >= 80:
    print('B - Great job! 👏')
elif score >= 70:
    print('C - Good work! 👍')
elif score >= 60:
    print('D - Keep trying! 💪')
else:
    print('F - Need help? 📚')

# Password checker
password = 'Python2024!'

print(f'Checking password: {password}')
print('-' * 30)

# Check length
if len(password) >= 8:
    print('✅ Length OK (8+ characters)')
else:
    print('❌ Too short (need 8+ characters)')

# Check for numbers
has_number = any(char.isdigit() for char in password)
if has_number:
    print('✅ Contains number')
else:
    print('❌ Add a number')

# Check for special characters
has_special = any(char in '!@#$%^&*' for char in password)
if has_special:
    print('✅ Contains special character')
else:
    print('❌ Add special character (!@#$%^&*)')

print('-' * 30)
if len(password) >= 8 and has_number and has_special:
    print('✅ PASSWORD SECURE!')
else:
    print('❌ PASSWORD WEAK - fix issues above')

